''
''
''
''
''
''
''
''
};
b64 = strjoin(parts, '');

% Base64 decode with compatibility fallback
try
    bytes = matlab.net.base64decode(b64);
catch
    decoder = java.util.Base64.getDecoder();
    jbytes = decoder.decode(uint8(b64));
    bytes = typecast(jbytes, 'uint8');
end

gzFile = [tempname, '.gz'];
fid = fopen(gzFile, 'w');
assert(fid ~= -1, 'Could not create temporary gzip file.');
fwrite(fid, bytes, 'uint8');
fclose(fid);

outDir = tempname;
mkdir(outDir);
files = gunzip(gzFile, outDir);
csvFile = files{1};

cachedT = readtable(csvFile, ...
    'TextType','string', ...
    'VariableNamingRule','preserve');

% Add heuristic region labels inferred from Population names
if ~ismember('Region', cachedT.Properties.VariableNames)
    pops = string(cachedT.Population);
    [uPops, ~, ic] = unique(pops);
    uRegions = strings(size(uPops));

    for ii = 1:numel(uPops)
        uRegions(ii) = map_population_to_region(uPops(ii));
    end

    cachedT.Region = uRegions(ic);

    % Place Region after Population for readability
    vars = string(cachedT.Properties.VariableNames);
    desired = ["Group","Locus","Allele","Population","Region","AlleleFrequency","IndividualsFrequency","SampleSize"];
    keep = desired(ismember(desired, vars));
    rest = vars(~ismember(vars, keep));
    cachedT = cachedT(:, cellstr([keep, rest]));
end


% Add ancestry group labels from embedded population lookup
if ~ismember('AncestryGroup', cachedT.Properties.VariableNames)
    pops = string(cachedT.Population);
    [uPopsA, ~, icA] = unique(pops);
    uAnc = strings(size(uPopsA));

    for ii = 1:numel(uPopsA)
        uAnc(ii) = map_population_to_ancestry(uPopsA(ii));
    end

    cachedT.AncestryGroup = uAnc(icA);

    % Put AncestryGroup at the end for readability
    vars = string(cachedT.Properties.VariableNames);
    base = ["Group","Locus","Allele","Population","Region","AlleleFrequency","IndividualsFrequency","SampleSize"];
    keep = [base(ismember(base, vars)), "AncestryGroup"];
    keep = keep(ismember(keep, vars));
    rest = vars(~ismember(vars, keep));
    cachedT = cachedT(:, cellstr([keep, rest]));
end


% Clean up temp files after caching in memory
try
    delete(gzFile);
    delete(csvFile);
    rmdir(outDir);
catch
end

T = cachedT;
end


function region = map_population_to_region(populationName)
% Best-effort heuristic mapping from AFND population strings to broad regions.
% Unknown is used when a population cannot be assigned confidently.

    s = lower(strtrim(string(populationName)));
    s = replace(s, "&", " and ");

    if contains_any(s, ["australia","australian"])
        region = "Australia";
        return;
    end

    if contains_any(s, ["new zealand","maori","samoa","samoan","tonga","tongan", ...
                        "fiji","fijian","papua","new guinea","guam","micronesia", ...
                        "micronesian","polynesia","polynesian","melanesia","melanesian", ...
                        "vanuatu","solomon islands","kiribati","palau","marshall islands", ...
                        "nauru","tuvalu","cook islands","tahiti","niue","tokelau", ...
                        "new caledonia","oceania"])
        region = "Oceania";
        return;
    end

    if contains_any(s, ["usa","united states","canada","quebec","ontario", ...
                        "pittsburgh","greenland","alaska","mexico"])
        region = "North America";
        return;
    end

    if contains_any(s, ["argentina","bolivia","brazil","chile","colombia","costa rica", ...
                        "cuba","dominican","dominica","ecuador","ecuadorean","el salvador", ...
                        "guatemala","guyana","haiti","honduras","jamaica","nicaragua", ...
                        "panama","paraguay","peru","puerto rico","suriname","trinidad", ...
                        "tobago","uruguay","venezuela","barbados","bahamas","belize", ...
                        "martinique","guadeloupe","caribbean"])
        region = "South and Central America";
        return;
    end

    if contains_any(s, ["albania","andorra","austria","belarus","belgium","bosnia", ...
                        "bulgaria","croatia","cyprus","czech","denmark","england","estonia", ...
                        "finland","france","germany","greece","hungary","iceland","ireland", ...
                        "italy","kosovo","latvia","lithuania","luxembourg","malta","moldova", ...
                        "montenegro","netherlands","norway","poland","portugal","romania", ...
                        "russia","serbia","slovak","slovenia","spain","sweden","switzerland", ...
                        "ukraine","united kingdom","scotland","wales","majorca","minorca", ...
                        "sardinia","basque","turin","azores","madeira","macedonia"])
        region = "Europe";
        return;
    end

    if contains_any(s, ["algeria","egypt","libya","morocco","tunisia","western sahara","north africa"])
        region = "North Africa";
        return;
    end

    if contains_any(s, ["angola","benin","botswana","burkina","burundi","cameroon", ...
                        "cape verde","central african","chad","comoros","congo", ...
                        "cote d'ivoire","ivory coast","djibouti","eritrea","eswatini", ...
                        "ethiopia","gabon","gambia","ghana","guinea","kenya","lesotho", ...
                        "liberia","madagascar","malawi","mali","mauritania","mauritius", ...
                        "mozambique","namibia","niger","nigeria","rwanda","senegal", ...
                        "seychelles","sierra leone","somalia","south africa","south sudan", ...
                        "sudan south","nuba","swaziland","tanzania","togo","uganda", ...
                        "zambia","zimbabwe","sub-saharan","sao tome"])
        region = "Sub-Saharan Africa";
        return;
    end

    if contains(s, "sudan")
        region = "North Africa";
        return;
    end

    if contains_any(s, ["armenia","azerbaijan","bahrain","georgia","iran","iraq","israel", ...
                        "jordan","kuwait","lebanon","oman","palestin","qatar","saudi", ...
                        "syria","turkey","uae","united arab emirates","yemen","gaza","caucasus"])
        region = "Western Asia";
        return;
    end

    if contains_any(s, ["kazakhstan","kyrgyz","kyrgyzstan","tajik","tajikistan", ...
                        "turkmen","turkmenistan","uzbek","uzbekistan","afghanistan"])
        region = "Central Asia";
        return;
    end

    if contains_any(s, ["bangladesh","bhutan","india","nepal","pakistan","sri lanka","maldives"])
        region = "South Asia";
        return;
    end

    if contains_any(s, ["brunei","cambodia","indonesia","laos","malaysia","myanmar", ...
                        "burma","philippines","singapore","thailand","timor","vietnam","borneo"])
        region = "South-East Asia";
        return;
    end

    if contains_any(s, ["china","chinese","hong kong","japan","japanese","korea","korean", ...
                        "mongolia","taiwan","tibet","han","manchu","uyghur","uighur","xinjiang"])
        region = "North-East Asia";
        return;
    end

    region = "Unknown";
end


